{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires calculating the Rydberg energy (binding energy) of an exciton and then scaling it to a specific principal quantum number. The decomposition separates the determination of the effective Rydberg constant from the application of the n-dependent scaling law.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Calculate the effective Rydberg energy (Ry*) of the exciton system. Use the given band gap (Eg) and the energy of the 1s exciton peak (E_exciton) to find the binding energy (E_b) for the n=1 state. Note that E_exciton = Eg - E_b. Ensure the binding energy is treated as a positive magnitude for the Rydberg constant."
    },
    {
      "label": "helper_2",
      "instructions": "Calculate the binding energy for the n=3 state using the hydrogenic scaling law E_n = Ry* / n^2. Pay close attention to the sign convention requested by the problem; if the question asks for the energy level relative to the band edge or the binding energy itself, ensure the sign reflects the physical state (typically negative for bound states or positive if referring to the magnitude of binding energy)."
    }
  ],
  "synthesis_brief": "Subtract the 1s exciton peak energy from the band gap to find the n=1 Rydberg energy. Divide this value by n^2 (where n=3) to find the energy for the n=3 state. Provide the final numerical value with the correct sign as specified by the context of Rydberg energy (typically negative for bound states relative to the conduction band edge)."
}

